// ExperienceTimeline.jsx
import React from "react";
import { VerticalTimeline, VerticalTimelineElement } from "react-vertical-timeline-component";
import "react-vertical-timeline-component/style.min.css";
import { FaBriefcase, FaUniversity } from "react-icons/fa";

const experiences = [
  {
    date: "2025",
    title: "Senior Product Manager - EY",
    icon: "briefcase",
    description: "Lideré la visión y roadmap de una plataforma de reporting financiero global.",
  },
  {
    date: "2021",
    title: "Product Manager - ExxonMobil",
    icon: "briefcase",
    description: "Automatización de licencias FlexLM en Azure, mejora de eficiencia operativa.",
  },
  {
    date: "2017",
    title: "Product Owner - J.P. Morgan",
    icon: "briefcase",
    description: "Implementación de DART con arquitectura event-driven y microservicios.",
  },
  {
    date: "2006",
    title: "Master of Engineering - UTN",
    icon: "university",
    description: "Ingeniería en Tecnología de la Información.",
  },
  {
    date: "2000",
    title: "Bachelor's Degree - UTN",
    icon: "university",
    description: "Licenciatura en Tecnología de la Información.",
  },
];

const iconStyles = {
  briefcase: {
    icon: <FaBriefcase color="white" />,
    gradient: "linear-gradient(to right, #000000, #ffffff)",
  },
  university: {
    icon: <FaUniversity color="white" />,
    gradient: "linear-gradient(to right, #0057ff, #ffffff)",
  },
};

const ExperienceTimeline = () => {
  const sortedExperiences = [...experiences].sort((a, b) => b.date.localeCompare(a.date));

  return (
    <div style={{ padding: "2rem 0" }}>
      <VerticalTimeline>
        {sortedExperiences.map((exp, index) => (
          <VerticalTimelineElement
            key={index}
            contentStyle={{
              background: iconStyles[exp.icon].gradient,
              color: "black",
              width: "fit-content",
              maxWidth: "90%",
              padding: "1rem",
            }}
            contentArrowStyle={{
              borderRight: "7px solid #000",
            }}
            date={exp.date}
            dateClassName="timeline-date"
            iconStyle={{ background: iconStyles[exp.icon].gradient }}
            icon={iconStyles[exp.icon].icon}
          >
            <h3 className="vertical-timeline-element-title">{exp.title}</h3>
            <p>{exp.description}</p>
          </VerticalTimelineElement>
        ))}
      </VerticalTimeline>
      <style>{`
        .timeline-date {
          font-size: 1rem;
          font-weight: bold;
          color: #333;
          top: -10px;
        }
        .vertical-timeline-element-content {
          display: inline-block;
        }
        .vertical-timeline-element-date {
          white-space: nowrap;
        }
      `}</style>
    </div>
  );
};

export default ExperienceTimeline;
